const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const xss = require('xss-clean');
const hpp = require('hpp');

const app = express();

// Security middleware
app.use(helmet()); // Sets various HTTP headers for security
app.use(xss()); // Prevents XSS attacks
app.use(hpp()); // Prevents HTTP Parameter Pollution

// Rate limiting to prevent brute force attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Body parsing middleware
app.use(express.json({ limit: '10kb' })); // Limit request payload size
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Health check endpoint with proper error handling
app.get('/health', (req, res) => {
  try {
    res.status(200).json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    res.status(500).json({ 
      error: 'Internal server error',
      message: 'Health check failed'
    });
  }
});

// Users endpoint with proper validation and error handling
app.get('/users', (req, res) => {
  try {
    // Validate query parameters if they exist
    const { page, limit } = req.query;

    // Basic validation for query parameters
    if (page && (isNaN(page) || page < 1)) {
      return res.status(400).json({ 
        error: 'Invalid parameter',
        message: 'Page must be a positive number'
      });
    }

    if (limit && (isNaN(limit) || limit < 1 || limit > 100)) {
      return res.status(400).json({ 
        error: 'Invalid parameter',
        message: 'Limit must be a number between 1 and 100'
      });
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.status(200).json(users);
  } catch (error) {
    // Log the actual error for debugging but don't expose it to client
    console.error('Error in /users endpoint:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      message: 'Failed to retrieve users'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({ 
    error: 'Not Found',
    message: 'Route not found'
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);
  res.status(500).json({ 
    error: 'Internal Server Error',
    message: 'An unexpected error occurred'
  });
});

// Listen with error handling
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
}).on('error', (error) => {
  console.error('Server failed to start:', error);
});

module.exports = app;

